#include<bits/stdc++.h>
using namespace std;
int sum[100010];
int lowbit(int x)
{
    return x&-x;
}
int n,m;
void update(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        sum[i]^=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans^=sum[i];
    }
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    while(m--)
    {
        int op,x,l,r;
        scanf("%d",&op);
        if(op==1)
        {
            scanf("%d%d",&l,&r);
            update(l,1);
            update(r+1,1);
        }
        else
        {
            scanf("%d",&x);
            printf("%d\n",query(x));
        }
    }
    return 0;
}
